// TextNode.jsx
import { useState, useMemo } from 'react';
import { Handle, Position } from 'reactflow';
import './node.css';

export const TextNode = ({ id, data }) => {
  const [currText, setCurrText] = useState(data?.text || '{{input}}');

  const handleTextChange = (e) => {
    setCurrText(e.target.value);
    data.text = e.target.value; // sync with React Flow node data
  };

  // Extract variables inside {{ }}
  const variables = useMemo(() => {
    const re = /\{\{\s*([a-zA-Z_$][\w$]*)\s*\}\}/g;
    const found = new Set();
    let m;
    while ((m = re.exec(currText)) !== null) {
      found.add(m[1]);
    }
    return Array.from(found);
  }, [currText]);

  return (
    <div className="vs-node text-node">
      <div className="vs-node-header">Text</div>
      <div className="vs-node-body">
        <label htmlFor={`${id}-text`}>
          Text:
          <input
            id={`${id}-text`}
            type="text"
            value={currText}
            onChange={handleTextChange}
            placeholder="Type here…"
          />
        </label>
      </div>

      {/* Dynamic input handles for variables */}
      {variables.map((v, i) => (
        <Handle
          key={`var-${v}`}
          type="target"
          position={Position.Left}
          id={`${id}-var-${v}`}
          style={{ top: `${30 + i * 20}px` }}
        />
      ))}

      {/* Output handle */}
      <Handle type="source" position={Position.Right} id={`${id}-output`} />
    </div>
  );
};
